export default {
  head() {
    return {
      title: this.$store.getters.headTitle,
       link: [{ rel: "icon", type: "image/x-icon", href: this.$store.getters.favicon}],
    };
  },
  layout: "user_lauout",
  data() {
    return {
      activeName: "all",
      userWallet: [
        {
          type: 'all',
          list: [],
          name: "全部记录",
          count: 0,
          page: 1,
        },
        {
          type: 'income',
          list: [],
          name: "收入记录",
          count: 0,
          page: 1,
        },
        {
          type: 'output',
          list: [],
          name: "消费记录",
          count: 0,
          page: 1,
        }
      ],
    };
  },
  async asyncData({$get, query}) {
    let wallet = {};
    let recodeList = [];
    let walletRes = await $get("user/myWallet");
    let recodeRes = await $get("user/accountLog", {
      params: {
        page_no: 1,
        page_size: 10,
        source: 1, 
        type: 0
      }
    })
    if(walletRes.code == 1) {
      wallet = walletRes.data;
    }
    if(recodeRes.code == 1) {
      recodeList = recodeRes.data.list
    }
    return {
      wallet,
      recodeList,
    }
  },
  fetch() {
    this.handleClick();
  },
  methods: {
    handleClick() {
      this.getRecodeList()
    },

    changePage(val) {
      this.userWallet.some((item) => {
        if (item.type == this.activeName) {
          item.page = val;
        }
      });
      this.getRecodeList();
    },

    async getRecodeList() {
      const {activeName, userWallet} = this;
      let type = activeName == 'all' ? 0 : activeName == 'income' ? 1 : 2
      const item = userWallet.find((item) => item.type == activeName);
      const {
        data: { list, count },
        code,
      } = await this.$get("user/accountLog", {
        params: {
          page_size: 10,
          page_no: item.page,
          type: type,
          source: 1
        },
      })
      if(code == 1) {
        this.recodeList = {list, count};
      }
    }
  },
  watch: {
    recodeList: {
      immediate: true,
      handler(val) {
        console.log('val:', val)
        this.userWallet.some(item => {
          if (item.type == this.activeName) {
            Object.assign(item, val);
            return true;
          }
        })
      }
    }
  }
};
